+            }
+        }
+
+        parts.join(" ")
+    }
+
+    /// Format as a JSON line.
+    #[must_use]
+    pub fn format_json(&self) -> String {
+        serde_json::to_string(self).unwrap_or_else(|_| "{}".to_string())
+    }
+}
